descriptor.controllerScript:
self.onInit = function() {};

self.onDataUpdated = function() {
    var data = self.ctx.data;
    if (data && data.length > 0 && data[0].data.length > 0) {
        var val = data[0].data[0][1];
        var isOn = (val === true || val === 'true' || val === 1 || val === '1');
        var led = self.ctx.$container[0].querySelector('#led');
        var lbl = self.ctx.$container[0].querySelector('#lbl');
        if (isOn) {
            led.style.backgroundColor = '#00e676';
            led.style.boxShadow = '0 0 20px 8px rgba(0,230,118,0.7)';
            lbl.textContent = 'ON';
            lbl.style.color = '#00c853';
        } else {
            led.style.backgroundColor = '#ff1744';
            led.style.boxShadow = '0 0 15px 5px rgba(255,23,68,0.6)';
            lbl.textContent = 'OFF';
            lbl.style.color = '#d50000';
        }
    }
};

self.onResize = function() {};
self.onDestroy = function() {};

